var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"노엘 양, 일어설 수 있겠나?","JPN":"ノエル君、立てるか？","ENG":"Noelle, can you get up?","TWN":"洛艾兒，你能站起來嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"INTERN_FENRIR_NULL_NULL","text":{"KOREA":"으으…. 세상이 핑핑 돌아요, 사장님….","JPN":"うう……世界がぐるぐる回ってます、社長……","ENG":"Urgh... The world is spinning, Boss...","TWN":"呃呃……整個世界都在轉，老闆……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"INTERN_FENRIR_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카, 라이카도 어서 한마디 해요.","JPN":"ライカ、ライカも早く何か言いなさいよ。","ENG":"Laika, you should also say something.","TWN":"萊卡，你也快點說句話吧。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L8_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"……어, 응.","JPN":"……あ、おお。","ENG":"...Huh? Okay.","TWN":"……喔，嗯。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"불법침입자라니 무슨 소리야, 꼬맹이.","JPN":"不法侵入者だなんて、何言ってんだよ、おこちゃま。","ENG":"What do you mean trespassing, kid?","TWN":"怎麼能說是非法入侵者呢，小鬼。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"저 애를 잘 봐. 무기를 들고 다니잖아.","JPN":"あいつを見てみろ。武器を持ってるだろ？","ENG":"Look at her! She's got a weapon!","TWN":"你看看她，手裡還拿著武器呢。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"내 날카로운 통찰력에 따르면 금품을 노리고 침입한 강도가 틀림없어.","JPN":"私の鋭い洞察力によると、きっと金品を狙って進入してきた強盗だな。","ENG":"With my keen observation skills, she's clearly breaking in to steal valuables.","TWN":"以我敏銳的觀察力來看，他們肯定是因為財迷心竅才登堂入室的強盜！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"좋은 지적이에요.","JPN":"立派な指摘ね。","ENG":"Good point.","TWN":"你說的沒錯。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L13_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그런데 제가 던진 헬멧은 왜 피했어요? 빗나가서 또 유리창 깨지면 물어낼 거예요?","JPN":"ところで、どうして私が投げたヘルメットを避けたの？　外れてまたガラス窓が割れたら弁償するつもり？","ENG":"But then, why did you evade the helmet I threw at you? Are you going to pay if it broke the window glass?","TWN":"不過你為什麼要躲開我扔的頭盔？萬一砸破玻璃，你會賠錢嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그게 왜 내 탓이냐. 네 조준이 엉터리라 그렇지.","JPN":"なんで人のせいにするんだよ？　あんたの照準がデタラメだからだろ。","ENG":"How would that be my fault? It just shows how bad your aim is.","TWN":"這怎麼能怪我？是你自己扔不準吧？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L16_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"억지는 그만 부려.","JPN":"屁理屈はそれくらいにして。","ENG":"Give it up, will you?","TWN":"少在那邊混淆視聽。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"헬멧 던진 건 그냥 넘어가 줄게. 어서 여기서 나가.","JPN":"ヘルメットを投げたのは目をつぶってあげるから。早くここから出て行って。","ENG":"I'll forgive you for throwing that helmet, so just leave.","TWN":"扔頭盔的事我不跟你們計較，你們快離開吧。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"나가야 할 건 그쪽이죠. 여긴 우리가 건틀렛 리그에 진출하기 위한 전초기지거든요.","JPN":"出ていくのはそっちでしょう？　ここは私たちがガントレットリーグに進出するための前哨基地なんです。","ENG":"You're the ones who should leave. This is our outpost for the Gauntlet League.","TWN":"該離開的人是你們。這裡是我們為參加聖鎧聯賽所準備的前哨基地。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그래. 다 쓰러져 가는 폐가를 정리하느라 엄청 고생했지.","JPN":"そうだ。倒れかかってる廃屋を掃除するのにどんだけ苦労したと思ってんだ。","ENG":"Yeah. Do you know how hard it was to clean up this dump?","TWN":"沒錯！為了收拾這個搖搖欲墜的破房子，我們差點沒累死！"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"무슨 사정 때문에 이러는지 몰라도, 너희들이 지금 하는 짓은 범죄야.","JPN":"どういう事情があるのかは知らないけど、あなたたちのやってることは犯罪だよ。","ENG":"I don't care what your reasons are, but you're committing a crime right now. ","TWN":"不管你們這麼做的原因是什麼，但你們現在的行為是犯罪。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"계속 안 나가고 버티면 경찰을 부르겠어.","JPN":"このまま出て行かないなら、警察を呼ぶから。","ENG":"If you don't leave, I'm going to call the police.","TWN":"如果你們堅持不肯離開，我就報警了。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"할말 없으니까 공권력을 동원하겠다는 건가요? 쓰레기 같은 어른이네요.","JPN":"対話では勝ち目がないから、公権力を動員するってことですか？　クズな大人ですね。","ENG":"Oh, you have nothing to say, so you're bringing cops into this? What a scumbag of an adult!","TWN":"說不過人家就要動用公共權力嗎？真是卑鄙的大人。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아무한테나 험한 말 쓰지 마. 세상엔 어린애라고 안 봐 주는 사람도 많으니까.","JPN":"乱暴な言い方するのは人を選んだ方がいいよ。世の中には子どもだからって手加減してくれない人も多いからね。","ENG":"You should be careful with what you say. This world is full of people who won't go easy on you just because you're a child.","TWN":"說話放尊重點，不是每個人都會因為你是小孩就網開一面的。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"훈계 잘하시네요. 교육 방송 출연해도 되겠어요.","JPN":"絵に描いたような説教ですね。教育番組とかに出たらどうですか？","ENG":"Thanks for the lecture. You should be teaching in kindergarten.","TWN":"很會教訓人嘛，我看你乾脆去當幼稚園老師好啦。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L31_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그런데 어쩌죠. 전 이 도시에서 살면서 어린애라고 봐주는 어른은 못 봤거든요.","JPN":"でも、残念でした。この街に暮らしてて、子どもだからって手加減してくれる大人に会ったことないんです。","ENG":"But you know, I've never seen an adult go easy on kids while living in this city.","TWN":"不過我在這裡活到這麼大，還從來沒見過因為我是小孩就網開一面的大人呢。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L32_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"말 잘했어, 꼬맹아.","JPN":"よく言った、おこちゃま。","ENG":"Well said, kid.","TWN":"說得好，小鬼。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그리고 말이야….","JPN":"それにな……","ENG":"And also...","TWN":"而且……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_PRIDE"}}}},{"id":"L34_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"이 도시엔 관광객이라고 안 봐주는 사람들도 많거든.","JPN":"この街には観光客に手加減してくれない人も多いんだよな。","ENG":"This city is full of people who aren't that generous to tourists either.","TWN":"這座城市對遊客也不是很友善。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_GUN_RELOAD_SMALL_02"},{"id":"L35_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"라이카? 어떡하려고 그래요?","JPN":"ライカ？　どうするつもりなの？","ENG":"Laika? What are you doing?","TWN":"你要做什麼？萊卡？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어떡하긴 뭘 어떡해. 저 녀석들을 잡아다 앉혀 놓고 확실하게 입막음해야지.","JPN":"どうするも何も。あいつらを捕まえて確実に口封じしないと。","ENG":"What do you mean? We need to keep them hostage and make sure they keep their mouths shut.","TWN":"什麼做什麼。當然是抓住這些傢伙，想辦法堵住他們的嘴。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L37_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"스키너가 이 꼴 보면 당장 짐싸서 나갈걸.","JPN":"スキナーがこれを見たら、その場で荷物まとめて出ていくに決まってる。","ENG":"If Skinner sees this, she's going to pack her bags and leave in a heartbeat.","TWN":"史金納要是回來看到這副情形，肯定二話不說收拾東西走人。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L38_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그, 그건 그렇지만….","JPN":"そ、それはそうだけど……","ENG":"T-true, but...","TWN":"是，是那樣沒錯……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그렇다고 납치 감금에 협박까지 하겠다고요?","JPN":"だからって、拉致・監禁に脅迫までするつもり？","ENG":"So we're going to keep them hostage and threaten them?","TWN":"所以我們要把他們綁起來軟禁嗎？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"어차피 짭새들이 쳐들어오면 우린 얄짤없이 강제 퇴거행이야.","JPN":"どうせ警察が来れば、私たちは間違いなく強制退去だ。","ENG":"If the cops come, the worst that can happen is getting kicked out.","TWN":"反正要是他們報警的話，到時候我們一定會被趕出去。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"그럼 이번 시즌 건틀렛 리그랑은 작별이지.","JPN":"そうなったら、今シーズンのガントレットリーグとはおさらばだ。","ENG":"That means saying goodbye to this season's Gauntlet League.","TWN":"那就得跟這次的聖鎧聯賽說再見囉。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"LAIKA_CANARY_NULL_NULL","text":{"KOREA":"당장 발등에 불 떨어진 건 내가 아니라 너 아냐?","JPN":"切羽詰まってるのはそっちだろ？","ENG":"Shouldn't you be more worried than I am right now?","TWN":"所以現在熱鍋上的螞蟻是你，不是我吧？"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"FELICETTE_CANARY_NULL_NULL","text":{"KOREA":"그래요. 인정하기 싫지만 어쩔 수 없네요.","JPN":"そうね。認めたくはないけど、仕方ないわね。","ENG":"I hate to admit it, but yes.","TWN":"沒錯，雖然不想承認，但也沒其他辦法。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"FELICETTE_CANARY_NULL_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"LAIKA_CANARY_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL_02"},{"id":"L49_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"아무래도…. 말로 해결하긴 힘들 것 같은데.","JPN":"どうやら……話では解決できそうにないね。","ENG":"I'm guessing... that we can't solve this peacefully.","TWN":"看來……你們是講不聽的。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L50_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"저 녀석들은 내가 상대할게. 노엘을 부탁해, 사장님.","JPN":"あいつらは私が相手する。ノエルを頼むよ、社長。","ENG":"I'll take on those two. Boss, keep Noelle safe.","TWN":"我來對付那些傢伙。老闆，洛艾兒就交給你。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"특이하게 생긴 방패로군. 조심하게.","JPN":"変わった盾だな。気をつけたまえ。","ENG":"That shield looks peculiar. Be careful.","TWN":"盾牌有點特別，你要小心。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"위험한 무기를 숨겨 뒀을지도 모르겠어.","JPN":"危険な武器を隠して持っているかもしれない。","ENG":"They might have a weapon hidden somewhere.","TWN":"她們或許藏有危險的武器。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"괜찮아. 나도 어설픈 수에 쉽게 당해 주진 않으니까. ","JPN":"大丈夫。私も下手な手に簡単にやられてあげるつもりはないから。 ","ENG":"It's fine. I won't fall for their cheap tricks.","TWN":"沒關係，我也不會輕易被蹩腳的伎倆打敗。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MINA_FENRIR_CHIEF_NULL","text":{"KOREA":"물러서 있어. 적당히 겁만 줄게.","JPN":"下がってて。適当に脅すだけにするよ。","ENG":"Take a step back. I'll just give them a little scare.","TWN":"閃開點，我稍微嚇嚇她們。"},"stage":{"bg":"DORMITORY_1","bgm":"THEMA_BOSS_PAWN","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MINA_FENRIR_CHIEF_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};